const s = $input.first().json;
const outs = s.outputs || {};
const c = s.content || {};
let base = String($env.MEDIA_PUBLIC_BASE || '');
while (base.endsWith('/')) base = base.slice(0, -1);
const reelPath = outs.reel_video_url || '';
if (!reelPath) {
  throw new Error('No reel_video_url. Check API response and that reel was built.');
}
const videoUrl = reelPath.startsWith('http') ? reelPath : base + reelPath;
if (!videoUrl.startsWith('https://')) {
  throw new Error('Instagram needs HTTPS video_url. Tunnel Velo (ngrok etc.) and set MEDIA_PUBLIC_BASE to https://your-tunnel (see n8n/README.md).');
}
const hook = c.hook || 'Travel inspiration';
const destLines = (c.destinations || [])
  .map((d) => '📍 ' + (d.destination || '') + '\n' + (d.caption || ''))
  .join('\n\n');
const tags = (c.hashtags || [])
  .map((t) => '#' + String(t).replace(/^#/, ''))
  .join(' ');
const cta = c.cta || '';
const caption = [hook, '', destLines, '', tags, '', cta].filter(Boolean).join('\n').trim();
const igId = $env.IG_USER_ID;
const token = $env.IG_ACCESS_TOKEN;
if (!igId || !token) {
  throw new Error('Set IG_USER_ID and IG_ACCESS_TOKEN (n8n Settings → Variables or Docker env).');
}
const params = new URLSearchParams({
  media_type: 'REELS',
  video_url: videoUrl,
  caption,
  access_token: token,
});
const createMediaUrl = 'https://graph.facebook.com/v21.0/' + igId + '/media?' + params.toString();
return [{ json: { createMediaUrl, igUserId: igId } }];
